fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let mode = required_f32(params, "mode").map_err(anyhow::Error::msg)?;
    let channelf = required_f32(params, "channelf").map_err(anyhow::Error::msg)?;
    let tuning = required_f32(params, "tuning").map_err(anyhow::Error::msg)?;
    let bias = required_f32(params, "bias").map_err(anyhow::Error::msg)?;
    let filter = required_f32(params, "filter").map_err(anyhow::Error::msg)?;
    let corr = required_f32(params, "corr").map_err(anyhow::Error::msg)?;
    let offset = required_f32(params, "offset").map_err(anyhow::Error::msg)?;
    let bendrange = required_f32(params, "bendrange").map_err(anyhow::Error::msg)?;
    let fastmode = required_bool(params, "fastmode").map_err(anyhow::Error::msg)?;
    let m00 = required_bool(params, "m00").map_err(anyhow::Error::msg)?;
    let m01 = required_bool(params, "m01").map_err(anyhow::Error::msg)?;
    let m02 = required_bool(params, "m02").map_err(anyhow::Error::msg)?;
    let m03 = required_bool(params, "m03").map_err(anyhow::Error::msg)?;
    let m04 = required_bool(params, "m04").map_err(anyhow::Error::msg)?;
    let m05 = required_bool(params, "m05").map_err(anyhow::Error::msg)?;
    let m06 = required_bool(params, "m06").map_err(anyhow::Error::msg)?;
    let m07 = required_bool(params, "m07").map_err(anyhow::Error::msg)?;
    let m08 = required_bool(params, "m08").map_err(anyhow::Error::msg)?;
    let m09 = required_bool(params, "m09").map_err(anyhow::Error::msg)?;
    let m10 = required_bool(params, "m10").map_err(anyhow::Error::msg)?;
    let m11 = required_bool(params, "m11").map_err(anyhow::Error::msg)?;
    let scale00 = required_f32(params, "scale00").map_err(anyhow::Error::msg)?;
    let scale01 = required_f32(params, "scale01").map_err(anyhow::Error::msg)?;
    let scale02 = required_f32(params, "scale02").map_err(anyhow::Error::msg)?;
    let scale03 = required_f32(params, "scale03").map_err(anyhow::Error::msg)?;
    let scale04 = required_f32(params, "scale04").map_err(anyhow::Error::msg)?;
    let scale05 = required_f32(params, "scale05").map_err(anyhow::Error::msg)?;
    let scale06 = required_f32(params, "scale06").map_err(anyhow::Error::msg)?;
    let scale07 = required_f32(params, "scale07").map_err(anyhow::Error::msg)?;
    let scale08 = required_f32(params, "scale08").map_err(anyhow::Error::msg)?;
    let scale09 = required_f32(params, "scale09").map_err(anyhow::Error::msg)?;
    let scale10 = required_f32(params, "scale10").map_err(anyhow::Error::msg)?;
    let scale11 = required_f32(params, "scale11").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_MODE, mode),
        (PORT_CTRL_CHANNELF, channelf),
        (PORT_CTRL_TUNING, tuning),
        (PORT_CTRL_BIAS, bias),
        (PORT_CTRL_FILTER, filter),
        (PORT_CTRL_CORR, corr),
        (PORT_CTRL_OFFSET, offset),
        (PORT_CTRL_BENDRANGE, bendrange),
        (PORT_CTRL_FASTMODE, if fastmode { 1.0 } else { 0.0 }),
        (PORT_CTRL_M00, if m00 { 1.0 } else { 0.0 }),
        (PORT_CTRL_M01, if m01 { 1.0 } else { 0.0 }),
        (PORT_CTRL_M02, if m02 { 1.0 } else { 0.0 }),
        (PORT_CTRL_M03, if m03 { 1.0 } else { 0.0 }),
        (PORT_CTRL_M04, if m04 { 1.0 } else { 0.0 }),
        (PORT_CTRL_M05, if m05 { 1.0 } else { 0.0 }),
        (PORT_CTRL_M06, if m06 { 1.0 } else { 0.0 }),
        (PORT_CTRL_M07, if m07 { 1.0 } else { 0.0 }),
        (PORT_CTRL_M08, if m08 { 1.0 } else { 0.0 }),
        (PORT_CTRL_M09, if m09 { 1.0 } else { 0.0 }),
        (PORT_CTRL_M10, if m10 { 1.0 } else { 0.0 }),
        (PORT_CTRL_M11, if m11 { 1.0 } else { 0.0 }),
        (PORT_CTRL_SCALE00, scale00),
        (PORT_CTRL_SCALE01, scale01),
        (PORT_CTRL_SCALE02, scale02),
        (PORT_CTRL_SCALE03, scale03),
        (PORT_CTRL_SCALE04, scale04),
        (PORT_CTRL_SCALE05, scale05),
        (PORT_CTRL_SCALE06, scale06),
        (PORT_CTRL_SCALE07, scale07),
        (PORT_CTRL_SCALE08, scale08),
        (PORT_CTRL_SCALE09, scale09),
        (PORT_CTRL_SCALE10, scale10),
        (PORT_CTRL_SCALE11, scale11),
    ];

    match layout {
        AudioChannelLayout::Mono => {
            let processor = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT], control_ports)?;
            Ok(BlockProcessor::Mono(Box::new(processor)))
        }
        AudioChannelLayout::Stereo => {
            let left = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT], control_ports)?;
            let right = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT], control_ports)?;
            Ok(BlockProcessor::Stereo(Box::new(DualMonoProcessor { left, right })))
        }
    }
}

struct DualMonoProcessor { left: lv2::Lv2Processor, right: lv2::Lv2Processor }
impl StereoProcessor for DualMonoProcessor {
    fn process_frame(&mut self, input: [f32; 2]) -> [f32; 2] {
        [self.left.process_sample(input[0]), self.right.process_sample(input[1])]
    }
}

fn schema() -> Result<ModelParameterSchema> { Ok(model_schema()) }

